// BRAND_IDS / hasBrand live in ./brandData so this file's only runtime export is
// the BrandLogo component (keeps React Fast Refresh happy).

export function BrandLogo({ app, size = 22 }: { app: string; size?: number }) {
  const b = BRANDS[app];
  if (!b) return null;
  return (
    <svg viewBox="0 0 24 24" width={size} height={size} fill={b.color} aria-hidden="true">
      <path d={b.path} />
    </svg>
  );
}
